24|func (m *dockerResourceManager) ListAgents(ctx context.Context) ([]dashboard.AgentResource, error) {
25|	if m.rt == nil {
26|		return []dashboard.AgentResource{}, nil
27|	}
28|	containers, err := m.rt.ListContainers(ctx, runtime.LabelResourceType)
29|	if err != nil {
30|		return nil, fmt.Errorf("list containers: %w", err)
31|	}
32|	agents := []dashboard.AgentResource{}
33|	for _, c := range containers {
34|		if c.ResourceType != runtime.ResourceTypeAgent {
