457|// This ONLY prunes OTel tables - audit JSONL is NEVER pruned by this method.
458|func (s *Store) Prune(ctx context.Context, retention time.Duration) (int64, error) {
459|	if err := ctx.Err(); err != nil {
460|		return 0, err
461|	}
462|	s.mu.Lock()
463|	defer s.mu.Unlock()
464|	db, err := s.database()
465|	if err != nil {
466|		return 0, err
467|	}
468|
469|	cutoff := time.Now().Add(-retention).UTC().UnixNano()
470|	tx, err := db.BeginTx(ctx, nil)
471|	if err != nil {
472|		return 0, fmt.Errorf("begin prune tx: %w", err)
473|	}
474|	defer func() { _ = tx.Rollback() }()
475|
476|	var deleted int64
477|	for _, statement := range []string{
478|		"DELETE FROM otel_spans WHERE start_time < ?",
479|		"DELETE FROM otel_logs WHERE timestamp < ?",
480|		"DELETE FROM otel_metrics WHERE timestamp < ?",
481|	} {
482|		if err := ctx.Err(); err != nil {
483|			return 0, err
484|		}
485|		result, err := tx.ExecContext(ctx, statement, cutoff)
486|		if err != nil {
487|			return 0, fmt.Errorf("prune otel table: %w", err)
488|		}
489|		n, err := result.RowsAffected()
490|		if err != nil {
491|			return 0, fmt.Errorf("read prune rows affected: %w", err)
492|		}
493|		deleted += n
494|	}
495|
496|	if err := tx.Commit(); err != nil {
497|		return 0, fmt.Errorf("commit prune tx: %w", err)
498|	}
499|	return deleted, nil
