195|// filterEnv returns a copy of env with the given variable names removed.
196|func filterEnv(env []string, names ...string) []string {
197|	result := make([]string, 0, len(env))
198|	for _, e := range env {
199|		skip := false
200|		for _, n := range names {
201|			if strings.HasPrefix(e, n+"=") {
202|				skip = true
203|				break
204|			}
205|		}
206|		if !skip {
207|			result = append(result, e)
208|		}
209|	}
