213|// buildDaemonStartCommand creates the exec.Cmd for starting the daemon subprocess.
214|// The caller must not close the returned logFile — the daemon subprocess inherits it.
215|func buildDaemonStartCommand(cmd *cobra.Command, daemonBinary string, paths *home.HomePaths) (*exec.Cmd, *os.File, error) {
216|	if err := os.MkdirAll(paths.Logs, 0700); err != nil {
217|		return nil, nil, fmt.Errorf("cannot create logs directory %s: %w", paths.Logs, err)
218|	}
219|	logPath := filepath.Join(paths.Logs, "daemon.log")
220|	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0600)
221|	if err != nil {
222|		return nil, nil, fmt.Errorf("cannot open daemon log file %s: %w", logPath, err)
223|	}
224|
225|	cmdDaemon := exec.Command(daemonBinary)
226|	cmdDaemon.Stdout = logFile
227|	cmdDaemon.Stderr = logFile
228|	cmdDaemon.Stdin = nil
229|
230|	homeDir, err := homeDirPath(cmd)
231|	if err != nil {
232|		_ = logFile.Close()
233|		return nil, nil, fmt.Errorf("cannot determine home directory: %w", err)
234|	}
235|
236|	// Always pass AGENTPAAS_HOME and AGENTPAAS_SOCKET to the daemon subprocess
237|	// explicitly. We strip any inherited copy via filterEnv to avoid duplicate
238|	// keys, then set the resolved values unconditionally — whether they
239|	// originated from --home/--socket flags or from the env vars. Without this,
240|	// a daemon spawned from an env-var-configured CLI would default to
241|	// ~/.agentpaas instead of $AGENTPAAS_HOME and fail to find its socket.
242|	cmdDaemon.Env = filterEnv(os.Environ(), "AGENTPAAS_HOME", "AGENTPAAS_SOCKET")
243|	cmdDaemon.Env = append(cmdDaemon.Env, "AGENTPAAS_HOME="+homeDir)
244|	if sock, _ := socketPath(cmd); sock != "" {
245|		cmdDaemon.Env = append(cmdDaemon.Env, "AGENTPAAS_SOCKET="+sock)
246|	}
