251|func runDaemonStart(cmd *cobra.Command) error {
252|	homeDir, err := homeDirPath(cmd)
253|	if err != nil {
254|		return fmt.Errorf("cannot determine home directory: %w", err)
255|	}
256|	paths := home.NewHomePaths(homeDir)
257|
258|	daemonBinary, err := daemonBinaryResolver()
259|	if err != nil {
260|		return err
261|	}
262|
263|	// Ensure home directory exists.
264|	if err := home.Ensure(paths); err != nil {
265|		return fmt.Errorf("home directory setup failed: %w", err)
266|	}
267|
268|	// Check if daemon is already running by looking for a non-stale PID.
269|	stale, err := home.IsStalePid(paths.PID)
270|	if err != nil {
271|		return fmt.Errorf("cannot check PID file: %w", err)
272|	}
273|	if !stale {
274|		return fmt.Errorf("daemon is already running (PID file %s is live)", paths.PID)
275|	}
276|
277|	// Clean stale files.
278|	if err := home.CleanStale(paths); err != nil {
279|		return fmt.Errorf("stale file cleanup failed: %w", err)
280|	}
281|
282|	// Start the daemon subprocess.
283|	cmdDaemon, _, err := buildDaemonStartCommand(cmd, daemonBinary, paths)
284|	if err != nil {
285|		return err
286|	}
287|
288|	if err := cmdDaemon.Start(); err != nil {
289|		return fmt.Errorf("cannot start daemon: %w", err)
290|	}
291|
292|	fmt.Printf("Daemon started (PID %d)\n", cmdDaemon.Process.Pid)
293|
294|	// The 1-second grace period balances two needs:
295|	//   - Fast enough for good CLI UX (user waits this long before "running").
296|	//   - Long enough that a crashing daemon (which exits in <100ms under normal
297|	//     load) is reliably caught even under heavy parallel test contention.
298|	// The canonical example: if the daemon binary is missing or the config is
299|	// bad, the process exits within milliseconds. A 1s window catches this with
300|	// high margin while keeping the happy-path snappy.
301|	waitCh := make(chan error, 1)
302|	go func() {
303|		waitCh <- cmdDaemon.Wait()
304|	}()
305|
306|	select {
307|	case err := <-waitCh:
308|		// Process exited during the grace period.
309|		exitCode := -1
310|		if cmdDaemon.ProcessState != nil {
311|			exitCode = cmdDaemon.ProcessState.ExitCode()
312|		}
313|		return fmt.Errorf("daemon exited immediately (exit code %d) — check logs at %s: %w",
314|			exitCode, paths.Logs, err)
315|	case <-time.After(1 * time.Second):
316|		// Daemon survived the grace period — consider it started.
317|		// The Wait() goroutine above remains blocked until the daemon eventually
318|		// exits; it will be reaped when this CLI process exits (benign leak).
319|		fmt.Println("Daemon is running. Use 'agent daemon status' to verify.")
320|		return nil
321|	}
