340|func runDaemonStop(cmd *cobra.Command) error {
341|	homeDir, err := homeDirPath(cmd)
342|	if err != nil {
343|		return fmt.Errorf("cannot determine home directory: %w", err)
344|	}
345|	paths := home.NewHomePaths(homeDir)
346|
347|	// Read PID file and send SIGTERM.
348|	pidData, err := os.ReadFile(paths.PID)
349|	if err != nil {
350|		if os.IsNotExist(err) {
351|			return fmt.Errorf("daemon is not running (no PID file at %s)", paths.PID)
352|		}
353|		return fmt.Errorf("cannot read PID file %s: %w", paths.PID, err)
354|	}
355|
356|	pidStr := strings.TrimSpace(string(pidData))
357|	if pidStr == "" {
358|		return fmt.Errorf("daemon is not running (PID file %s is empty)", paths.PID)
359|	}
360|
361|	pid, err := strconv.Atoi(pidStr)
362|	if err != nil {
363|		return fmt.Errorf("invalid PID %q in %s: %w", pidStr, paths.PID, err)
364|	}
365|
366|	proc, err := os.FindProcess(pid)
367|	if err != nil {
368|		return fmt.Errorf("cannot find process %d: %w", pid, err)
369|	}
370|
371|	if err := proc.Signal(syscall.SIGTERM); err != nil {
372|		return fmt.Errorf("cannot send SIGTERM to PID %d: %w", pid, err)
373|	}
374|
375|	// Wait for process to exit.
376|	waitDone := make(chan struct{})
377|	go func() {
378|		_, _ = proc.Wait()
379|		select {
380|		case waitDone <- struct{}{}:
381|		default:
382|		}
383|	}()
384|
385|	select {
386|	case <-waitDone:
387|		fmt.Printf("Daemon (PID %d) stopped\n", pid)
388|	case <-time.After(10 * time.Second):
389|		fmt.Printf("Daemon (PID %d) did not exit within 10 seconds — sending SIGKILL\n", pid)
390|		_ = proc.Signal(syscall.SIGKILL)
391|		// Best-effort reap the zombie.
392|		go func() { _, _ = proc.Wait() }()
393|	}
